from __future__ import annotations

from datetime import UTC, datetime
from enum import StrEnum
from typing import Literal

from pydantic import BaseModel, ConfigDict, Field, field_validator, model_validator

from aegis_services.features import canonical_hash

SYNTHETIC_LIMITATIONS = (
    "SYNTHETIC DEMO ONLY. This dataset and its labels were generated by AegisAI "
    "scenarios to test software contracts. Results do not measure UNSW-NB15 "
    "performance, real-network intrusion detection, generalization, zero-day "
    "detection, production readiness, or prevention suitability. The model is "
    "offline-only and cannot create or modify alerts or prevention actions."
)


class SyntheticLabel(StrEnum):
    BENIGN_LIKE = "synthetic_benign_like"
    INTRUSION_LIKE = "synthetic_intrusion_like"


class ScenarioFamily(StrEnum):
    BACKGROUND_MIXED_SERVICES = "background_mixed_services"
    BACKGROUND_SPARSE_IDLE = "background_sparse_idle"
    BACKGROUND_BURSTY = "background_bursty"
    SCAN_LIKE_FANOUT = "scan_like_fanout"
    FAILURE_LIKE_SEQUENCE = "failure_like_sequence"
    CONNECTION_RATE_LIKE = "connection_rate_like"
    AMBIGUOUS_OVERLAP = "ambiguous_overlap"
    MISSING_UNKNOWN_BOUNDARY = "missing_unknown_boundary"


class SyntheticPartition(StrEnum):
    TRAINING = "training"
    VALIDATION = "validation"
    TEST = "test"


class SyntheticScenarioCatalogV1(BaseModel):
    model_config = ConfigDict(extra="forbid", frozen=True)

    contract: Literal["synthetic-flow-scenario/v1"] = "synthetic-flow-scenario/v1"
    version: Literal["1.0.0"] = "1.0.0"
    global_seed: Literal[20260714] = 20260714
    families: tuple[ScenarioFamily, ...] = tuple(ScenarioFamily)
    labels: tuple[SyntheticLabel, ...] = tuple(SyntheticLabel)
    maximum_flows: int = Field(default=10_000, ge=1, le=10_000)
    maximum_groups: int = Field(default=120, ge=1, le=120)
    payload_allowed: Literal[False] = False
    pcap_allowed: Literal[False] = False
    network_allowed: Literal[False] = False
    real_dataset_emulation_allowed: Literal[False] = False
    alert_side_effects_allowed: Literal[False] = False
    prevention_allowed: Literal[False] = False

    @model_validator(mode="after")
    def require_closed_catalog(self) -> SyntheticScenarioCatalogV1:
        if self.families != tuple(ScenarioFamily):
            raise ValueError(
                "synthetic scenario catalog must contain the approved ordered families"
            )
        if self.labels != tuple(SyntheticLabel):
            raise ValueError("synthetic label catalog must contain the approved labels")
        return self

    @property
    def catalog_hash(self) -> str:
        return canonical_hash(self)


class SyntheticTargetV1(BaseModel):
    model_config = ConfigDict(extra="forbid", frozen=True)

    contract: Literal["synthetic-target/v1"] = "synthetic-target/v1"
    example_identity_hash: str = Field(pattern=r"^[a-f0-9]{64}$")
    label: SyntheticLabel
    scenario_family: ScenarioFamily
    group_identity_hash: str = Field(pattern=r"^[a-f0-9]{64}$")
    partition: SyntheticPartition


class SyntheticArtifactV1(BaseModel):
    model_config = ConfigDict(extra="forbid", frozen=True)

    kind: Literal["canonical_flows", "targets", "features"]
    object_ref: str = Field(pattern=r"^[a-f0-9-]{36}$")
    media_type: str = Field(min_length=1, max_length=96)
    sha256: str = Field(pattern=r"^[a-f0-9]{64}$")
    size_bytes: int = Field(ge=1, le=67_108_864)
    row_count: int = Field(ge=1, le=10_000)
    column_count: int | None = Field(default=None, ge=1, le=46)


class SyntheticQualityReportV1(BaseModel):
    model_config = ConfigDict(extra="forbid", frozen=True)

    contract: Literal["synthetic-quality-report/v1"] = "synthetic-quality-report/v1"
    total_flows: int = Field(ge=1, le=10_000)
    total_groups: int = Field(ge=1, le=120)
