class SyntheticLeakageReportV1(BaseModel):
    model_config = ConfigDict(extra="forbid", frozen=True)

    contract: Literal["synthetic-leakage-report/v1"] = "synthetic-leakage-report/v1"
    banned_model_columns_found: tuple[str, ...] = ()
    cross_partition_event_duplicates: Literal[0] = 0
    cross_partition_vector_duplicates: Literal[0] = 0
    cross_partition_group_duplicates: Literal[0] = 0
    cross_partition_near_duplicates: Literal[0] = 0
